class DeepLinkHandler(context: Context) {
    private val host = "myapp"
    private val schemes = listOf("myapp")

    fun handleDeepLink(uri: Uri) {
        if (!isAllowedRoute(uri)) {
            return
        }

        when (uri.pathSegments[0]) {
            "profile" -> navigateToProfileActivity(uri)
            "payment" -> navigateToPaymentConfirmationActivity(uri)
        }
    }

    private fun isAllowedRoute(uri: Uri): Boolean {
        return schemes.contains(uri.scheme) && host == uri.host
    }

    private fun navigateToProfileActivity(uri: Uri) {
        val profileId = uri.pathSegments[1]
        val intent = Intent(context, ProfileActivity::class.java).apply {
            putExtra("profile_id", profileId)
        }
        context.startActivity(intent)
    }

    private fun navigateToPaymentConfirmationActivity(uri: Uri) {
        val paymentId = uri.pathSegments[1]
        val intent = Intent(context, PaymentConfirmationActivity::class.java).apply {
            putExtra("payment_id", paymentId)
        }
        context.startActivity(intent)
    }
}